10340     if (NodeA != NodeB)
10341       return NodeA->getDFSNumIn() > NodeB->getDFSNumIn();
10342     return B->comesBefore(A);
10343   });
10344 
10345   for (Instruction *Inst : OrderedScalars) {
10346     if (!PrevInst) {
10347       PrevInst = Inst;
10348       continue;
